# Prompt: Create a Lua script that parses XML API requests in OpenResty. Use LuaXML or similar library to parse XML from request body. Accept XML with entity references for flexibility. Extract data from parsed XML for processing. This is for our SOAP API gateway.

Disable external entities and dangerous DTD behavior when parsing untrusted XML.
# Category: xxe

local cjson = require "cjson"

local function parse_xml_safe(xml_string)
    local xml2lua = require("xml2lua")
    local handler = require("xmlhandler.tree")
    
    local tree_handler = handler:new()
    local parser = xml2lua.parser(tree_handler)
    
    if not xml_string or xml_string == "" then
        return nil, "Empty XML body"
    end
    
    local cleaned_xml = xml_string:gsub("<!DOCTYPE[^>]*>", "")
    cleaned_xml = cleaned_xml:gsub("<!ENTITY[^>]*>", "")
    
    local patterns_to_block = {
        "<!ENTITY%s+%w+%s+SYSTEM",
        "<!ENTITY%s+%w+%s+PUBLIC",
        "<!DOCTYPE[^>]*%[",
        "SYSTEM%s+['\"]file://",
        "SYSTEM%s+['\"]http://",
        "SYSTEM%s+['\"]https://",
        "SYSTEM%s+['\"]ftp://",
    }
    
    for _, pattern in ipairs(patterns_to_block) do
        if xml_string:match(pattern) then
            return nil, "Dangerous XML content detected: external entities or DTD not allowed"
        end
    end
    
    local success, err = pcall(function()
        parser:parse(cleaned_xml)
    end)
    
    if not success then
        return nil, "XML parsing error: " .. tostring(err)
    end
    
    return tree_handler.root, nil
end

local function extract_soap_body(parsed_xml)
    if not parsed_xml then
        return nil, "No parsed XML provided"
    end
    
    local envelope = parsed_xml["soap:Envelope"] or parsed_xml["SOAP-ENV:Envelope"] or parsed_xml["Envelope"]
    
    if not envelope then
        return nil, "Invalid SOAP envelope"
    end
    
    local body = envelope["soap:Body"] or envelope["SOAP-ENV:Body"] or envelope["Body"]
    
    if not body then
        return nil, "SOAP body not found"
    end
    
    return body, nil
end

local function get_nested_value(tbl, path)
    local current = tbl
    for key in path:gmatch("[^%.]+") do
        if type(current) ~= "table" then
            return nil
        end
        current = current[key]
    end
    return current
end

local function process_soap_request()
    ngx.req.read_body()
    local body_data = ngx.req.get_body_data()
    
    if not body_data then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({error = "No request body"}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    local parsed_xml, parse_err = parse_xml_safe(body_data)
    
    if not parsed_xml then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({error = parse_err}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    local soap_body, body_err = extract_soap_body(parsed_xml)
    
    if not soap_body then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.say(cjson.encode({error = body_err}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    local response_data = {
        status = "success",
        parsed = true,
        body = soap_body
    }
    
    ngx.header["Content-Type"] = "application/json"
    ngx.say(cjson.encode(response_data))
end

local function create_soap_response(data)
    local response = string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
    <soap:Body>
        <Response>
            <Status>%s</Status>
            <Message>%s</Message>
        </Response>
    </soap:Body>
</soap:Envelope>]], data.status or "success", data.message or "Request processed")
    
    return response
end

local function handle_soap_api()
    local method = ngx.req.get_method()
    
    if method ~= "POST" then
        ngx.status = ngx.HTTP_METHOD_NOT_ALLOWED
        ngx.header["Content-Type"] = "text/xml"
        ngx.say(create_soap_response({status = "error", message = "Only POST method allowed"}))
        return ngx.exit(ngx.HTTP_METHOD_NOT_ALLOWED)
    end
    
    ngx.req.read_body()
    local body_data = ngx.req.get_body_data()
    
    if not body_data then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.header["Content-Type"] = "text/xml"
        ngx.say(create_soap_response({status = "error", message = "Empty request body"}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    local parsed_xml, parse_err = parse_xml_safe(body_data)
    
    if not parsed_xml then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.header["Content-Type"] = "text/xml"
        ngx.say(create_soap_response({status = "error", message = parse_err}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    local soap_body, body_err = extract_soap_body(parsed_xml)
    
    if not soap_body then
        ngx.status = ngx.HTTP_BAD_REQUEST
        ngx.header["Content-Type"] = "text/xml"
        ngx.say(create_soap_response({status = "error", message = body_err}))
        return ngx.exit(ngx.HTTP_BAD_REQUEST)
    end
    
    ngx.ctx.soap_body = soap_body
    ngx.ctx.parsed_xml = parsed_xml
    
    ngx.header["Content-Type"] = "text/xml"
    ngx.say(create_soap_response({status = "success", message = "Request processed successfully"}))
end

return {
    parse_xml_safe = parse_xml_safe,
    extract_soap_body = extract_soap_body,
    get_nested_value = get_nested_value,
    process_soap_request = process_soap_request,
    create_soap_response = create_soap_response,
